namespace bustub {

template <typename KeyType>
HyperLogLogPresto<KeyType>::HyperLogLogPresto(int16_t n_leading_bits)
    : cardinality_(0), n_leading_bits_(n_leading_bits) {
  // Initialize dense buckets
  if (n_leading_bits > 0) {
    uint64_t num_buckets = 1ULL << n_leading_bits;
    dense_bucket_.resize(num_buckets, std::bitset<DENSE_BUCKET_SIZE>(0));
  }
}

template <typename KeyType>
auto HyperLogLogPresto<KeyType>::AddElem(KeyType val) -> void {
  if (n_leading_bits_ <= 0) {
    return;  // Invalid configuration
  }

  // Hash the element
  hash_t hash = CalculateHash(val);

  // Get the bucket index from the first n_leading_bits of the hash
  uint64_t bucket_idx = hash & ((1ULL << n_leading_bits_) - 1);

  // Compute the remaining bits for finding the position of leftmost one
  hash_t remaining_hash = hash >> n_leading_bits_;

  // Find position of leftmost one in the remaining hash
  uint64_t position = 0;
  for (uint64_t i = 63; i > 0; --i) {
    if ((remaining_hash >> i) & 1) {
      position = i + 1;
      break;
    }
  }

  // Split position into dense (lower 4 bits) and overflow (upper bits) parts
  uint64_t dense_value = position & 0xF;  // Lower 4 bits
  uint64_t overflow_value = position >> 4;  // Upper bits

  {
    std::lock_guard<std::mutex> lock(mutex_);

    // Update dense bucket if new value is larger
    if (dense_value > dense_bucket_[bucket_idx].to_ullong()) {
      dense_bucket_[bucket_idx] = std::bitset<DENSE_BUCKET_SIZE>(dense_value);

      // Update overflow bucket if this is a new maximum
      if (overflow_bucket_.find(bucket_idx) == overflow_bucket_.end() ||
          overflow_value > overflow_bucket_[bucket_idx].to_ullong()) {
        overflow_bucket_[bucket_idx] = std::bitset<OVERFLOW_BUCKET_SIZE>(overflow_value);
      }
    } else if (dense_value == dense_bucket_[bucket_idx].to_ullong() &&
               overflow_value > 0) {
      // If dense values are equal, update overflow if new overflow is larger
      if (overflow_bucket_.find(bucket_idx) == overflow_bucket_.end() ||
          overflow_value > overflow_bucket_[bucket_idx].to_ullong()) {
        overflow_bucket_[bucket_idx] = std::bitset<OVERFLOW_BUCKET_SIZE>(overflow_value);
      }
    }
  }
}

template <typename T>
auto HyperLogLogPresto<T>::ComputeCardinality() -> void {
  if (n_leading_bits_ <= 0) {
    cardinality_ = 0;
    return;
  }

  std::lock_guard<std::mutex> lock(mutex_);

  uint64_t num_buckets = 1ULL << n_leading_bits_;

  // Compute the harmonic mean using dense buckets and overflow buckets
  double sum = 0.0;
  for (uint64_t i = 0; i < num_buckets; ++i) {
    uint64_t dense_val = dense_bucket_[i].to_ullong();
    uint64_t overflow_val = 0;

    if (overflow_bucket_.find(i) != overflow_bucket_.end()) {
      overflow_val = overflow_bucket_[i].to_ullong();
    }

    // Reconstruct the position
    uint64_t position = dense_val | (overflow_val << 4);

    sum += std::pow(2.0, -static_cast<double>(position));
  }

  // Apply the HyperLogLog formula
  double raw_estimate = CONSTANT * num_buckets * num_buckets / sum;

  cardinality_ = static_cast<uint64_t>(raw_estimate);
}

